package unverified;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair3845DifferenceFindingTest {

    private final ClonePair3845 subject = new ClonePair3845();

    /**
     * Generated by Codex (GPT-5.5).
     */
    @Test
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{new double[]{Double.NaN}, new double[]{Double.NaN}};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((double[]) values[0], (double[]) values[1]), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((double[]) values[0], (double[]) values[1]), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Double(NaN)",
            null,
            "java.lang.Object[][double[][NaN],double[][NaN]]",
            "java.lang.Object[][double[][NaN],double[][NaN]]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Double(0.0)",
            null,
            "java.lang.Object[][double[][NaN],double[][NaN]]",
            "java.lang.Object[][double[][NaN],double[][NaN]]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
